+package com.facebook.buck.android;
+
+import static org.junit.Assert.assertThat;
+import static org.junit.Assert.assertTrue;
+
+import com.facebook.buck.io.filesystem.ProjectFilesystem;
+import com.facebook.buck.model.BuildTargetFactory;
+import com.facebook.buck.rules.BuildRuleResolver;
+import com.facebook.buck.rules.DefaultSourcePathResolver;
+import com.facebook.buck.rules.DefaultTargetNodeToBuildRuleTransformer;
+import com.facebook.buck.rules.FakeBuildContext;
+import com.facebook.buck.rules.FakeBuildableContext;
+import com.facebook.buck.rules.PathSourcePath;
+import com.facebook.buck.rules.SingleThreadedBuildRuleResolver;
+import com.facebook.buck.rules.SourcePath;
+import com.facebook.buck.rules.SourcePathResolver;
+import com.facebook.buck.rules.SourcePathRuleFinder;
+import com.facebook.buck.rules.TargetGraph;
+import com.facebook.buck.step.Step;
+import com.facebook.buck.testutil.FakeProjectFilesystem;
+import com.google.common.collect.ImmutableList;
+import java.lang.reflect.Constructor;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import java.util.Optional;
+import org.junit.Test;
+
+public class GenerateStringSourceMapTriggerTest {
+
+  @Test
+  public void getBuildStepsContainsGenStringSourceMapStep() throws Exception {
+    ProjectFilesystem filesystem = new FakeProjectFilesystem();
+    BuildRuleResolver ruleResolver =
+        new SingleThreadedBuildRuleResolver(
+            TargetGraph.EMPTY, new DefaultTargetNodeToBuildRuleTransformer());
+    SourcePathRuleFinder ruleFinder = new SourcePathRuleFinder(ruleResolver);
+    SourcePathResolver pathResolver = DefaultSourcePathResolver.from(ruleFinder);
+
+    GenerateStringSourceMap rule =
+        createRule(
+            filesystem,
+            ruleFinder,
+            new PathSourcePath(filesystem, Paths.get("android_res/R.txt")),
+            new PathSourcePath(filesystem, Paths.get("android_res/res")));
+
+    ImmutableList<? extends Step> steps =
+        rule.getBuildSteps(
+            FakeBuildContext.withSourcePathResolver(pathResolver), new FakeBuildableContext());
+
+    assertTrue(steps.size() >= 2);
+    assertThat(
+        steps.stream().anyMatch(step -> step.getShortName().equals("build_string_source_map")),
+        org.hamcrest.Matchers.is(true));
+    assertThat(
+        steps.stream().anyMatch(step -> step instanceof GenStringSourceMapStep),
+        org.hamcrest.Matchers.is(true));
+  }
+
+  private GenerateStringSourceMap createRule(
+      ProjectFilesystem filesystem,
+      SourcePathRuleFinder ruleFinder,
+      SourcePath rDotTxtFile,
+      SourcePath resourceDirectory)
+      throws Exception {
+    Constructor<?> constructor = GenerateStringSourceMap.class.getDeclaredConstructors()[0];
+    constructor.setAccessible(true);
+    if (constructor.getParameterTypes().length == 3) {
+      return (GenerateStringSourceMap)
+          constructor.newInstance(
+              BuildTargetFactory.newInstance("//apps/sample:strings"),
+              filesystem,
+              ruleFinder);
+    }
+
+    return (GenerateStringSourceMap)
+        constructor.newInstance(
+            BuildTargetFactory.newInstance("//apps/sample:strings"),
+            filesystem,
+            ruleFinder,
+            rDotTxtFile,
+            new TestFilteredResourcesProvider(resourceDirectory));
+  }
+
+  private static class TestFilteredResourcesProvider implements FilteredResourcesProvider {
+    private final ImmutableList<SourcePath> resDirectories;
+
+    private TestFilteredResourcesProvider(SourcePath resourceDirectory) {
+      this.resDirectories = ImmutableList.of(resourceDirectory);
+    }
+
+    @Override
+    public ImmutableList<SourcePath> getResDirectories() {
+      return resDirectories;
+    }
+
+    @Override
+    public ImmutableList<Path> getStringFiles() {
+      return ImmutableList.of();
+    }
+
+    @Override
+    public Optional<com.facebook.buck.rules.BuildRule> getResourceFilterRule() {
+      return Optional.empty();
+    }
+
+    @Override
+    public boolean hasResources() {
+      return true;
+    }
+
+    @Override
+    public Optional<SourcePath> getOverrideSymbolsPath() {
+      return Optional.empty();
+    }
+  }
+}
